mapper.select:
SELECT * FROM orders WHERE user_id = #{userId}
ORDER BY create_time DESC
LIMIT #{offset}, #{limit}

mapper.update:
UPDATE orders
SET status = #{status}, update_time = NOW()
WHERE id = #{id}

UPDATE orders
SET status = #{status}, update_time = NOW()
WHERE id = #{id} AND status = #{expectedStatus}

mapper.select:
SELECT *
FROM orders
WHERE status = 0
  AND create_time < #{cutoff}
ORDER BY create_time ASC
LIMIT #{limit}
